const CLI_FRAMES=['·','✢\uFE0E','✳\uFE0E','✶\uFE0E','✻\uFE0E','✽\uFE0E'];let _cliIdx=0,_cliIv=null;const _cliEls=new Set();function _regCli(el){_cliEls.add(el);}function _unregCli(el){_cliEls.delete(el);}function _startCli(){if(_cliIv)return;_cliIv=setInterval(()=>{_cliIdx=(_cliIdx+1)%CLI_FRAMES.length;const f=CLI_FRAMES[_cliIdx];_cliEls.forEach(el=>{if(el.isConnected)el.textContent=f;else _cliEls.delete(el);});},400);}function _stopCli(){if(_cliIv){clearInterval(_cliIv);_cliIv=null;}_cliEls.clear();}
