    if(!hdr){hdr=document.createElement('div');hdr.className='str-tl-header open stl-loading';hdr.onclick=function(){this.classList.toggle('open');};hdr.innerHTML='<svg class="stl-arrow" viewBox="0 0 24 24"><path d="M9 18l6-6-6-6"/></svg><span class="stl-summary"></span>';stl.appendChild(hdr);body=document.createElement('div');body.className='str-tl-body';stl.appendChild(body);}
