async function regen(messageId,idx){if(S.streaming||!S.cid)return;S.streaming=true;const _mw=document.getElementById('msgs-wrap');if(_mw)_mw._userScrolled=false;updBtn();if(idx!==undefined)hideMsgsFrom(idx);const sd=appStr();let ft='';let fthink='';let _clock=null;let _contentStarted=false;let _resumeThink='';try{const params={conversation_id:S.cid,model:gMdl()};if(messageId)params.message_id=messageId;const res=await api('regenerate',params,true);if(!res){S.streaming=false;updBtn();rMsgs();return;}const rd=res.body.getReader(),dc=new TextDecoder();let buf='';while(true){const{done,value}=await rd.read();if(done)break;buf+=dc.decode(value,{stream:true});const _li=buf.lastIndexOf('\n');if(_li===-1)continue;const ls=buf.substring(0,_li).split('\n');buf=buf.substring(_li+1);for(const ln of ls){const tr=ln.trim();if(!tr.startsWith('data: '))continue;const d=tr.slice(6);if(d==='[DONE]')continue;try{const p=JSON.parse(d);if(p.type==='thinking'){fthink+=p.text;if(!_clock)_clock=_startThinkClock();_strOnThinking(sd,p.text,_clock);}if(p.type==='content'){if(!_contentStarted)_contentStarted=true;ft+=p.text;_strOnContent(sd,p.text,ft);}if(p.type==='tool_start'||p.type==='tool_result'||p.type==='tool_done')_strOnTool(sd,p);if(p.type==='done_meta'){const mc=getModelColor(p.model);const tk=p.token_count?p.token_count+' tokens':'';const existMeta=sd.querySelector('#str-meta');if(existMeta){existMeta.id='';existMeta.querySelector('.mm-name').textContent=_displayName(p.model);if(tk){let infoEl=existMeta.querySelector('.mm-info');if(!infoEl){infoEl=document.createElement('div');infoEl.className='mm-info';existMeta.querySelector('.mm-body').appendChild(infoEl);}infoEl.innerHTML='<span>'+tk+'</span>';}}else{const md=document.createElement('div');md.className='msg-meta';md.innerHTML=_avatarHtml(mc)+'<div class="mm-body"><div class="mm-name">'+E(_displayName(p.model))+'</div>'+(tk?'<div class="mm-info"><span>'+tk+'</span></div>':'')+'</div>';const mcEl=sd.querySelector('#str-flow');if(mcEl)mcEl.insertBefore(md,mcEl.firstChild);}}}catch(x){}}}}catch(e){S._aborted=(e.name==='AbortError');if(!S._aborted)toast('失败');if(!ft&&sd.parentNode)sd.remove();}_strFinalize(sd,fthink,_clock);S.streaming=false;S.ac=null;updBtn();if(S._aborted&&ft){S.msgs.push({role:'assistant',content:ft,thinking_content:fthink||null,_partial:true});S._aborted=false;}else if(S.cid){try{const d3=await api('get_messages',{conversation_id:S.cid});_storeTree(d3);if(S._lastThinkMeta){_attachThinkMeta(S._lastThinkMeta.fthink,S._lastThinkMeta._resumeThink,S._lastThinkMeta.duration);}_cacheConv();_syncStreamDom(sd);rMsgs();}catch(x){}}}
async function regenUser(m,idx){if(S.streaming||!S.cid)return;S.streaming=true;const _mw=document.getElementById('msgs-wrap');if(_mw)_mw._userScrolled=false;updBtn();hideMsgsFrom(idx);const msgsEl=document.getElementById('msgs');const tmpUser=document.createElement('div');tmpUser.className='msg user';let tmpContent=E(m.content).replace(/\n/g,'<br>');let tmpImgs='';if(m.attachments&&m.attachments.length>0){const imgAtts=m.attachments.filter(a=>a.type==='image'&&a.url);if(imgAtts.length)tmpImgs='<div class="msg-imgs">'+imgAtts.map(a=>'<img src="'+a.url+'" loading="lazy">').join('')+'</div>';const docAtts=m.attachments.filter(a=>a.type==='document');if(docAtts.length)tmpImgs+='<div class="msg-docs">'+docAtts.map(a=>'<div class="doc-chip"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><path d="M14 2v6h6"/></svg><span>'+E(a.name)+'</span></div>').join('')+'</div>';}tmpUser.innerHTML=tmpImgs+(tmpContent?'<div class="mc">'+tmpContent+'</div>':'');msgsEl.appendChild(tmpUser);const sd=appStr();let ft='';let fthink='';let _clock=null;let _contentStarted=false;let _resumeThink='';try{const chatParams={conversation_id:S.cid,message:m.content,model:gMdl(),is_regen:true};const prevMsg=idx>0?S.msgs[idx-1]:null;if(prevMsg?.id)chatParams.parent_id=prevMsg.id;if(m.attachments){const imgUrls=m.attachments.filter(a=>a.type==='image'&&a.url).map(a=>a.url);if(imgUrls.length>0)chatParams.images=imgUrls;const docs=m.attachments.filter(a=>a.type==='document');if(docs.length>0)chatParams.documents=docs.map(d=>({name:d.name,content:d.text||''}));}const res=await api('chat',chatParams,true);if(!res){S.streaming=false;updBtn();rMsgs();return;}const rd=res.body.getReader(),dc=new TextDecoder();let buf='';while(true){const{done,value}=await rd.read();if(done)break;buf+=dc.decode(value,{stream:true});const _li=buf.lastIndexOf('\n');if(_li===-1)continue;const ls=buf.substring(0,_li).split('\n');buf=buf.substring(_li+1);for(const ln of ls){const tr=ln.trim();if(!tr.startsWith('data: '))continue;const d=tr.slice(6);if(d==='[DONE]')continue;try{const p=JSON.parse(d);if(p.type==='meta'&&p.conversation_id)S.cid=p.conversation_id;if(p.type==='thinking'){fthink+=p.text;if(!_clock)_clock=_startThinkClock();_strOnThinking(sd,p.text,_clock);}if(p.type==='content'){if(!_contentStarted)_contentStarted=true;ft+=p.text;_strOnContent(sd,p.text,ft);}if(p.type==='tool_start'||p.type==='tool_result'||p.type==='tool_done')_strOnTool(sd,p);if(p.type==='done_meta'){const mc=getModelColor(p.model);const tk=p.token_count?p.token_count+' tokens':'';const existMeta=sd.querySelector('#str-meta');if(existMeta){existMeta.id='';existMeta.querySelector('.mm-name').textContent=_displayName(p.model);if(tk){let infoEl=existMeta.querySelector('.mm-info');if(!infoEl){infoEl=document.createElement('div');infoEl.className='mm-info';existMeta.querySelector('.mm-body').appendChild(infoEl);}infoEl.innerHTML='<span>'+tk+'</span>';}}else{const md=document.createElement('div');md.className='msg-meta';md.innerHTML=_avatarHtml(mc)+'<div class="mm-body"><div class="mm-name">'+E(_displayName(p.model))+'</div>'+(tk?'<div class="mm-info"><span>'+tk+'</span></div>':'')+'</div>';const mcEl=sd.querySelector('#str-flow');if(mcEl)mcEl.insertBefore(md,mcEl.firstChild);}}}catch(x){}}}}catch(e){S._aborted=(e.name==='AbortError');if(!S._aborted)toast('失败');if(!ft&&sd.parentNode)sd.remove();}_strFinalize(sd,fthink,_clock);S.streaming=false;S.ac=null;updBtn();if(S._aborted&&ft){S.msgs.push({role:'assistant',content:ft,thinking_content:fthink||null,_partial:true});S._aborted=false;}else if(S.cid){try{const d3=await api('get_messages',{conversation_id:S.cid});_storeTree(d3);if(S._lastThinkMeta){_attachThinkMeta(S._lastThinkMeta.fthink,S._lastThinkMeta._resumeThink,S._lastThinkMeta.duration);}_cacheConv();_syncStreamDom(sd);rMsgs();}catch(x){}}}
